 3→import com.pinterest.ktlint.core.Rule
 4→import com.pinterest.ktlint.core.ast.ElementType
 5→import com.pinterest.ktlint.core.ast.ElementType.PACKAGE_DIRECTIVE
 6→import com.pinterest.ktlint.core.ast.nextCodeSibling
 7→import org.jetbrains.kotlin.com.intellij.lang.ASTNode
 8→
 9→/**
10→ * https://kotlinlang.org/docs/coding-conventions.html#naming-rules
11→ */
12→public class PackageNameRule : Rule("package-name") {
13→    override fun beforeVisitChildNodes(
14→        node: ASTNode,
15→        autoCorrect: Boolean,
16→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
17→    ) {
18→        node
19→            .takeIf { node.elementType == PACKAGE_DIRECTIVE }
20→            ?.firstChildNode
21→            ?.nextCodeSibling()
22→            ?.takeIf { it.elementType == ElementType.DOT_QUALIFIED_EXPRESSION || it.elementType == ElementType.REFERENCE_EXPRESSION }
23→            ?.let { expression ->
24→                if (expression.text.contains('_')) {
25→                    // The Kotlin inspections (preference > Editor > Inspections) for 'Package naming convention' allows
26→                    // underscores as well. But as this has been forbidden by KtLint since early versions, this is still
27→                    // prohibited.
28→                    emit(expression.startOffset, "Package name must not contain underscore", false)
29→                } else if (!expression.text.matches(VALID_PACKAGE_NAME_REGEXP)) {
30→                    emit(expression.startOffset, "Package name contains a disallowed character", false)
31→                }
32→            }
33→    }
34→
35→    private companion object {
36→        val VALID_PACKAGE_NAME_REGEXP = Regex("[a-z_][a-zA-Z\\d_]*(\\.[a-z_][a-zA-Z\\d_]*)*")
37→    }
38→}
