class PackageNameRuleNordicTest {
    private val packageNameRuleAssertThat = assertThatRule { PackageNameRule() }

    @Test
    fun `Given a package name containing nordic characters then do not emit`() {
        val code =
            """
            package føø.båå.zöö
            """.trimIndent()
        packageNameRuleAssertThat(code).hasNoLintViolations()
    }
}
