344→public fun ASTNode.lineIndent(): String {
345→    var leaf = this.prevLeaf()
346→    while (leaf != null) {
347→        if (leaf.elementType == WHITE_SPACE && leaf.textContains('\n')) {
348→            return leaf.text.substring(leaf.text.lastIndexOf('\n') + 1)
349→        }
350→        leaf = leaf.prevLeaf()
351→    }
352→    return ""
